import{DateTime}from"luxon";import{Converter}from"showdown";import{parse as twemojiParse}from"twemoji";class ElementFormatter{get customEmotes(){return/(:don:|:katsu:|:desuwa:|:dirt:|:armagan:)/g}get emojiTable(){return{don:"/static/svg/don.svg",katsu:"/static/svg/katsu.svg",desuwa:"/static/svg/desuwa.svg",dirt:"/static/image/dirt_small.gif",armagan:"/static/image/armagan_small.gif"}}formatAll(){this.dateFormat(),this.markdownFormat(),this.twemojiFormat(),this.emoteFormat()}dateFormat(){for(let e of document.getElementsByClassName("date-format"))try{e.innerHTML=DateTime.fromISO(e.innerHTML).toFormat("fff")}catch(e){console.error(e)}}markdownFormat(){for(let e of document.getElementsByClassName("markdown-format")){let t=new Converter;try{e.innerHTML=t.makeHtml(e.innerHTML)}catch(e){console.error(e)}}}twemojiFormat(){for(let e of document.getElementsByClassName("twemoji-format"))try{twemojiParse(e)}catch(e){console.error(e)}}emoteFormat(){for(let e of document.getElementsByClassName("emote-format"))try{e.innerHTML=e.innerHTML.replace(this.customEmotes,e=>{let t=document.createElement("img");return t.src=this.emojiTable[e.replace(/:/g,"")],t.className="emoji",t.draggable=!1,t.alt=e,t})}catch(e){console.error(e)}}}export{ElementFormatter};